var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"모, 모네는 살면서 저런 건 실제로 처음 봤슴다!","JPN":"モ、モネはあんなの初めてみるっす！","ENG":"M-Mone has never seen anything like this before, ma’am!","TWN":"莫…莫妮活到現在，第一次看到那樣的東西唷！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"세상에……. 태풍은 많이 봤어도 토네이도 얘기는 들은 적 없는데…….","JPN":"そんな……台風はあってもトルネードがこの村に発生した話は聞いたことがありません……","ENG":"Oh no... We’ve had storms before, but never a tornado...","TWN":"天啊……雖然經歷過很多次颱風，但龍捲風我還是第一次聽說呢…"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"오오, 나 몸이 점점 밀려나, 아빠!","JPN":"おお、身体が押されてるよ、パパ！","ENG":"Daddy, I’m getting pushed away, wow!","TWN":"哦哦，爸爸！我好像快飛走咧！"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"맞다! 저걸 타고 날아가면 마법의 대륙으로 떠날 수 있을까?","JPN":"そうだ！　あれに乗って飛んでいけば魔法の大陸に行けるのかな？","ENG":"Maybe this tornado will take me to another magical world!","TWN":"哇！乘著那個是不是可以直接飛上月球？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"아니, 그건 착한 토네이도가 하는 일이란다. 저건 사람을 해치는 아주 나쁜 토네이도야.","JPN":"いや、それは善良なトルネードがすることだよ。あれは人を傷つける非常に悪いトルネードだ。","ENG":"No, that’s what a good tornado does. This is a bad tornado that hurts people.","TWN":"不，上月球要搭阿波羅11號，而且龍捲風只會搞破壞。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"사람을 해쳐? 그런 건 싫어!","JPN":"人を傷つける？　そんなのイヤだよ！","ENG":"It hurts people? No!","TWN":"搞破壞？我不喜歡搞破壞！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"SUYEON_COFFIN_SUMMER_NULL","text":{"KOREA":"움직이는 속도가 무척 빠르군요. 저대로 두면 마을을 그대로 덮치겠습니다.","JPN":"速度がとても速いです。このままだと、村を直撃するでしょう。","ENG":"It’s coming in fast. It will hit the village soon.","TWN":"移動的速度好快，放著不管的話，恐怕會直撲村莊。"},"stage":{"bg":"VILLAGE1","slots":{"L":null,"C":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"으음……. 가장 안 좋은 예상이 맞아떨어졌군.","JPN":"ううむ……不吉な予感が的中してしまったな。","ENG":"Um... this is the worst case scenario...","TWN":"呃…真是屋漏偏逢連夜雨。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SUYEON_COFFIN_SUMMER_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LONELY_NPC_NULL_NULL","text":{"KOREA":"드라코! 저건 <color=#ffd34c>그거</color> 때문이죠?! 기상조절 시스템!","JPN":"ドラコ！　あれは<color=#ffd34c>アレ</color>のせいですね！？　気象調節システム！","ENG":"Dracasia! It’s because of <color=#ffd34c>that</color> thing, right? The Weather Control System!","TWN":"德拉克！是因為<color=#ffd34c>那個</color> 吧？！氣象調節系統！"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"맞아. 쓰지 말라고 했는데 결국에는 이 꼴이 나 버렸어.","JPN":"そうだよ。使うなって言ったのに結局この様だ。","ENG":"Yes. I told them not to use it, yet here we are.","TWN":"沒錯。我有說過不要用，結果還是這樣。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"DRACO_NPC_SUMMER_NULL","text":{"KOREA":"돈만 많은 멍청이들 같으니…….","JPN":"脳みそに金しか入ってないバカな連中……","ENG":"Those rich, arrogant idiots...","TWN":"那群有錢就是任性的傢伙…"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"LONELY_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"DRACO_NPC_SUMMER_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MASK_FLORA_SUMMER_NULL","text":{"KOREA":"기상조절 시스템? 그건 관리국 직할 도시에만 설치된 물건 아닌가요?","JPN":"気象調節システム？　それは管理局直轄都市にだけ設置された物ではないのですか？","ENG":"The Weather Control System? That device is installed only in Administration Direct Control Cities, right?","TWN":"氣象調節系統？那東西不是只設置在管理局直轄市嗎？"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L25_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그러고 보니 최근에 마크…… 아니, 아는 사람한테서 들은 적이 있어.","JPN":"そういえば最近マーク……いや、知り合いから聞いたことある。","ENG":"Mark—I mean someone I know told me told me recently...","TWN":"這麼說來，馬克……不是，我好像聽朋友說過。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_FLORA_SUMMER_NULL","text":{"KOREA":"그로니아 반군이 샤레이드에 설치하려고 했던 기상조절 시스템을 탈취했다나 봐.","JPN":"グロニア反乱軍がシャレードに設置しようとしていた気象調節システムを奪取したみたい。","ENG":"Gronia rebels stole the Weather Control System that was originally meant for Charade.","TWN":"原本要設置在查雷德的氣象調節系統，似乎落入格羅尼亞叛軍的手裡。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"SPEAR_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MASK_FLORA_SUMMER_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"군자금을 마련하려고 블랙 네트워크를 통해 판매했나 보군요.","JPN":"軍資金を調達しようとブラックネットワークを通じて販売したようですね。","ENG":"Then they sold it through the Dark Network to fund their operations.","TWN":"很可能是因為要籌措軍事費用，才會透過黑色網絡出售。"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEADER_MAID_NULL_NULL","text":{"KOREA":"하지만 저렇게 위험한 물건을 겨우 돈 몇 푼 때문에 아무한테나 넘기다니…….","JPN":"しかし、あんなに危険な物をわずかなお金のために一般人に渡すなんて……","ENG":"They shouldn’t be selling so dangerous a device just for money...","TWN":"但他們竟然為了幾個錢，就把那麼危險的東西輕易給出去……"},"stage":{"bg":"VILLAGE1","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEADER_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}}]`);export{e as default};